sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    if (isLoading || newValue === '') {
        return;
    }
    if (!newValue == '') {
        g_form.setSectionDisplay('device_details', true);
        g_form.setSectionDisplay('delivery_details', true);
    }
    // If the newValue field is cleared (empty), hide the sections

    g_form.getReference('device_name', getDetails);
}

function getDetails(details) {
    g_form.setValue('model', details.model_number);
    g_form.setValue('device_description', details.short_description);
    g_form.setValue('price', details.new_price);
    g_form.setValue('waranty_expiration', details.warranty_expiration);
}
